function makeApiKeyConfig(key) {
  // Private variable held in scope
  const apiKey = key;
  return {
    // Function accesses apiKey via closure
    getHeaders: () => {
      return { 'Authorization': `Bearer ${apiKey}` };
    }
  };
}
// Create instance carrying private key
const client = makeApiKeyConfig('SECRET_API_TOKEN_123');
// Retrieve headers without accessing variable directly
console.log(client.getHeaders());

/* Output:
{
  'Authorization': 'Bearer SECRET_API_TOKEN_123'
}
*/

async function fetchUserProfile(userId) {
  try {
    // Simulate network delay and fetch data
    const user = await new Promise((resolve) => {
      setTimeout(() => resolve({ id: userId, name: 'Alice' }), 100);
    });
    // Return formatted result
    return `User: ${user.name}`;
  } catch (err) {
    // Catch and handle error boundaries
    return 'Error loading user';
  }
}
// Invoke async function and print output
fetchUserProfile(42).then(console.log);

/* Output:
User: Alice
*/

