const prices = [10, 20, 30, 40];
// map is a HOF taking a callback function
const taxedPrices = prices.map(price => price * 1.1);
// reduce is a HOF aggregating values
const total = taxedPrices.reduce((sum, price) => sum + price, 0);

console.log(taxedPrices);
console.log(total);

/* Output:
[ 11, 22, 33, 44 ]
110
*/

function debounce(func, delay) {
  let timeoutId;
  return function (...args) {
    // Reset timer on every trigger
    clearTimeout(timeoutId);
    // Execute after delay passes
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}
// Mock search function
const performSearch = (q) => console.log('Searching:', q);
const debouncedSearch = debounce(performSearch, 300);
// Multiple invocations only trigger once
debouncedSearch('a');
debouncedSearch('ab');

/* Output (after 300ms):
Searching: ab
*/

const user = {
  profile: { name: 'Bob' },
  role: null
};
// Destructuring with default values
const { profile: { name } } = user;
// Optional Chaining & Nullish Coalescing
const role = user.role?.type ?? 'Guest';
// Spread operator to clone objects
const updatedUser = { ...user, active: true };

console.log(name, '|', role, '|', updatedUser.active);

/* Output:
Bob | Guest | true
