const list = document.createElement('ul');
// Attach a single listener to the parent container
list.addEventListener('click', (e) => {
  // Check if the clicked target is a list item
  if (e.target && e.target.tagName === 'LI') {
    console.log('Clicked Item:', e.target.textContent);
  }
});
// Dynamic creation of child nodes requires no new listeners!
const item = document.createElement('li');
item.textContent = 'Apples';
list.appendChild(item);

// Simulate click event for demonstration
item.click();

/* Output:
Clicked Item: Apples
*/

